def problemas_da_categoria(categoria: str):
    """Lista de dicts (problema/solucao/risco) para a categoria informada."""
    return [p for p in CATALOGO_PROBLEMAS if p["categoria"] == categoria]


def buscar_problema(categoria: str, problema: str):
    for p in CATALOGO_PROBLEMAS:
        if p["categoria"] == categoria and p["problema"] == problema:
            return p
    return None
